insert into public.exercicios (id,nome,grupo_muscular,padrao_movimento,equipamento,musculos,execucao,cue,erro_comum,variacoes,peso_esforco_base,casa_ok) values
('ex_supino_reto_com_barra','Supino reto com barra','peito','empurrar horizontal','barra','["peitoral maior","tríceps","deltoide anterior"]'::jsonb,'Deite no banco, pegada pouco além dos ombros, desça a barra até o meio do peito e empurre.','Escápulas retraídas e pés firmes; barra desce controlada.','Saltar o peito / abrir demais os cotovelos.','["Supino inclinado","Supino declinado","Supino pegada fechada"]'::jsonb,1.3,false),
('ex_supino_inclinado_com_barra','Supino inclinado com barra','peito','empurrar horizontal','barra','["peitoral superior","deltoide anterior","tríceps"]'::jsonb,'Banco a 30–45°, desça a barra até a clavícula alta e empurre.','Foco na parte alta do peito; cotovelos ~45°.','Inclinar demais (vira ombro).','["Supino inclinado com halteres","Máquina inclinada"]'::jsonb,1.3,false),
('ex_supino_inclinado_com_halteres','Supino inclinado com halteres','peito','empurrar horizontal','halter','["peitoral superior","deltoide anterior"]'::jsonb,'Banco inclinado, halteres na linha do peito alto, empurre juntando levemente em cima.','Amplitude maior que a barra; controla a descida.','Bater os halteres no topo e perder tensão.','["Supino reto halteres","Crucifixo inclinado"]'::jsonb,1.2,false),
('ex_crucifixo_com_halteres','Crucifixo com halteres','peito','isolado','halter','["peitoral maior"]'::jsonb,'Deitado, braços semiflexionados, abra em arco e junte sem estender total.','Arco fixo; sente o alongamento do peito.','Transformar em supino dobrando o cotovelo.','["Crucifixo inclinado","Crossover"]'::jsonb,0.9,false),
('ex_crossover_na_polia','Crossover na polia','peito','isolado','cabo','["peitoral maior","peitoral inferior"]'::jsonb,'Polias altas, passo à frente, junte as mãos à frente do quadril.','Contrai o peito no final; tronco levemente à frente.','Usar impulso do corpo.','["Crossover baixo→alto","Crucifixo na polia"]'::jsonb,0.9,false),
('ex_flexao_de_braco','Flexão de braço','peito','empurrar horizontal','peso corporal','["peitoral","tríceps","core"]'::jsonb,'Mãos na largura do peito, corpo reto, desça o peito ao chão e empurre.','Abdômen firme; corpo em prancha.','Cair o quadril / não descer.','["Flexão inclinada","Flexão declinada","Flexão diamante"]'::jsonb,1,true),
('ex_supino_maquina','Supino máquina','peito','empurrar horizontal','maquina','["peitoral","tríceps"]'::jsonb,'Ajuste o banco, pegada na linha do peito, empurre sem travar o cotovelo.','Ótimo pra volume seguro e falha.','Selim alto demais (vira ombro).','["Máquina inclinada","Peck deck"]'::jsonb,1.1,false),
('ex_peck_deck_voador','Peck deck (voador)','peito','isolado','maquina','["peitoral maior"]'::jsonb,'Sentado, cotovelos na almofada, junte à frente contraindo o peito.','Isola o peito; segura 1s na contração.','Puxar com o ombro.','["Crucifixo","Crossover"]'::jsonb,0.9,false),
('ex_barra_fixa_pull_up','Barra fixa (pull-up)','costas','puxar vertical','peso corporal','["latíssimo","romboides","bíceps"]'::jsonb,'Pegada pronada além dos ombros, puxe até o queixo passar a barra.','Puxa com os cotovelos pra baixo; peito pra barra.','Balançar / meia amplitude.','["Pull-up supinada (chin-up)","Puxada na máquina","Barra assistida"]'::jsonb,1.3,true),
('ex_puxada_frontal_na_polia','Puxada frontal na polia','costas','puxar vertical','cabo','["latíssimo","romboides","bíceps"]'::jsonb,'Sentado, puxe a barra até a parte alta do peito, cotovelos pra baixo.','Peito aberto; não jogue o tronco.','Puxar na nuca / usar impulso.','["Puxada supinada","Puxada triângulo"]'::jsonb,1.2,false),
('ex_remada_curvada_com_barra','Remada curvada com barra','costas','puxar horizontal','barra','["latíssimo","romboides","trapézio","posterior"]'::jsonb,'Tronco inclinado ~45°, puxe a barra ao umbigo, cotovelos rentes.','Coluna neutra; puxa com as costas, não os braços.','Arredondar a lombar.','["Remada pendlay","Remada pegada supinada"]'::jsonb,1.3,false),
('ex_remada_unilateral_com_halter','Remada unilateral com halter','costas','puxar horizontal','halter','["latíssimo","romboides"]'::jsonb,'Apoio no banco, puxe o halter ao quadril, cotovelo colado.','Puxa o cotovelo pra trás e cima; contrai a escápula.','Rotacionar o tronco pra levantar mais peso.','["Remada serrote","Remada na máquina"]'::jsonb,1.1,false),
('ex_remada_baixa_na_polia','Remada baixa na polia','costas','puxar horizontal','cabo','["latíssimo","romboides","trapézio médio"]'::jsonb,'Sentado, puxe o triângulo ao abdômen, peito aberto.','Escápulas juntam no final; tronco estável.','Balançar pra frente e trás.','["Remada com corda","Remada barra reta"]'::jsonb,1.1,false),
('ex_pulldown_com_braco_reto','Pulldown com braço reto','costas','isolado','cabo','["latíssimo"]'::jsonb,'Em pé, braços retos, empurre a barra até as coxas em arco.','Isola o dorsal sem bíceps.','Dobrar o cotovelo (vira tríceps).','["Pullover com halter"]'::jsonb,0.9,false),
('ex_levantamento_terra','Levantamento terra','costas','dobrar quadril','barra','["eretores","glúteo","posterior","trapézio","latíssimo"]'::jsonb,'Barra no meio do pé, coluna neutra, empurre o chão e estenda o quadril.','Peito alto, barra colada; quadril e ombro sobem juntos.','Arredondar a lombar / puxar com as costas.','["Terra romeno","Terra sumô","Terra com trap bar"]'::jsonb,1.4,false),
('ex_encolhimento_trapezio','Encolhimento (trapézio)','costas','isolado','halter','["trapézio superior"]'::jsonb,'Em pé com halteres, encolha os ombros em direção às orelhas.','Segura 1s no topo; sem rodar os ombros.','Rodar os ombros (desgasta articulação).','["Encolhimento na barra","Encolhimento na máquina"]'::jsonb,0.9,true),
('ex_desenvolvimento_com_barra','Desenvolvimento com barra','ombro','empurrar vertical','barra','["deltoide","tríceps","trapézio"]'::jsonb,'Sentado ou em pé, barra na altura do queixo, empurre acima da cabeça.','Core firme; não hiperestenda a lombar.','Arquear demais as costas.','["Desenvolvimento halteres","Push press"]'::jsonb,1.3,false),
('ex_desenvolvimento_com_halteres','Desenvolvimento com halteres','ombro','empurrar vertical','halter','["deltoide","tríceps"]'::jsonb,'Sentado, halteres na linha das orelhas, empurre juntando levemente em cima.','Amplitude completa; punhos neutros.','Bater os halteres e perder tensão.','["Arnold press","Desenvolvimento máquina"]'::jsonb,1.2,false),
('ex_elevacao_lateral','Elevação lateral','ombro','isolado','halter','["deltoide medial"]'::jsonb,'Em pé, eleve os halteres até a linha dos ombros, cotovelo levemente flexionado.','Lidera com o cotovelo; sem impulso.','Balançar o corpo / subir com trapézio.','["Elevação na polia","Elevação na máquina"]'::jsonb,0.9,true),
('ex_elevacao_frontal','Elevação frontal','ombro','isolado','halter','["deltoide anterior"]'::jsonb,'Eleve o halter à frente até a altura dos olhos.','Controla a descida; tronco estável.','Usar embalo do quadril.','["Elevação com anilha","Elevação na polia"]'::jsonb,0.9,true),
('ex_crucifixo_invertido_rear_delt','Crucifixo invertido (rear delt)','ombro','isolado','halter','["deltoide posterior","romboides"]'::jsonb,'Tronco inclinado, abra os halteres em arco apertando as escápulas.','Foco no deltoide posterior; sem trapézio.','Usar peso demais e virar remada.','["Rear delt na polia","Peck deck invertido"]'::jsonb,0.9,true),
('ex_face_pull','Face pull','ombro','puxar horizontal','cabo','["deltoide posterior","trapézio médio","rotadores"]'::jsonb,'Corda na altura do rosto, puxe separando as mãos rumo às orelhas.','Ótimo corretivo postural; cotovelos altos.','Puxar baixo (vira remada).','["Face pull com elástico"]'::jsonb,0.9,true),
('ex_arnold_press','Arnold press','ombro','empurrar vertical','halter','["deltoide","tríceps"]'::jsonb,'Comece com palmas pra você, gire enquanto empurra acima.','Rotação suave; ativa 3 porções do ombro.','Girar rápido demais.','["Desenvolvimento halteres"]'::jsonb,1.1,false),
