-- ============================================================
-- Quest — migration 0013: biblioteca viva de exercicios (v8) — 59 exercicios
-- ------------------------------------------------------------
-- Banco consultavel com ficha detalhada (musculos, execucao, cue, erro comum,
-- variacoes), grupo/padrao/equipamento, casa_ok e peso_esforco_base. Leitura p/
-- autenticados. Expansivel. ON CONFLICT DO NOTHING (idempotente).
-- ============================================================

create table if not exists public.exercicios (
  id                 text primary key,
  nome               text not null,
  grupo_muscular     text not null,
  padrao_movimento   text,
  equipamento        text,
  musculos           jsonb,
  execucao           text,
  cue                text,
  erro_comum         text,
  variacoes          jsonb,
  peso_esforco_base  numeric not null default 1,
  casa_ok            boolean not null default false
);

alter table public.exercicios enable row level security;
drop policy if exists exercicios_select on public.exercicios;
create policy exercicios_select on public.exercicios for select using (auth.role() = 'authenticated');

on conflict (id) do nothing;
